#include <vector>
#include <priority_queue>
#include <climits>
#include <unordered_map>
#include <cmath>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        graph[u].emplace_back(v, w);
    }

    // Dijkstra's algorithm with state (node, switch_used)
    // switch_used is a boolean indicating whether the switch at the node has been used
    // We use a priority queue to track the minimum cost to reach each state
    // Each state is (cost, node, switch_used)
    // We use a distance array to track the minimum cost to reach each state
    // Since each node can have two states (switch used or not), we use a 2D array
    vector<vector<long long>> dist(n, vector<long long>(2, LONG_MAX));
    dist[0][0] = 0;  // Start at node 0 with switch not used

    // Priority queue: (cost, node, switch_used)
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<pair<long long, pair<long long, long long>>>> pq;
    pq.emplace(0, make_pair(0, 0));

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long u = pq.top().second.first;
        long long switch_used = pq.top().second.second;
        pq.pop();

        // If we've reached the destination, return the cost
        if (u == n - 1) {
            return cost;
        }

        // If this is not the shortest path to this state, skip
        if (cost > dist[u][switch_used]) {
            continue;
        }

        // Explore neighbors
        for (const auto& [v, w] : graph[u]) {
            // Regular edge: go directly
            long long new_cost = cost + w;
            if (new_cost < dist[v][switch_used]) {
                dist[v][switch_used] = new_cost;
                pq.emplace(new_cost, make_pair(v, switch_used));
            }

            // Reverse edge: if switch hasn't been used at u
            if (!switch_used) {
                long long new_cost_rev = cost + 2 * w;
                if (new_cost_rev < dist[v][1]) {
                    dist[v][1] = new_cost_rev;
                    pq.emplace(new_cost_rev, make_pair(v, 1));
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}
